import React, { useState, useMemo } from 'react';
import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';
import { Picker } from '@react-native-picker/picker';

interface Variation {
  size: string;
  color: string;
  stock: number;
  price: number;
}

interface Props {
  variations: Variation[];
  onVariationChange: (variation: Variation | null, quantity: number) => void;
}

const ProductVariationSelector: React.FC<Props> = ({ variations, onVariationChange }) => {
  const [selectedSize, setSelectedSize] = useState<string>('');
  const [selectedColor, setSelectedColor] = useState<string>('');
  const [quantity, setQuantity] = useState<number>(1);

  // Extraire les tailles et couleurs uniques
  const sizes = [...new Set(variations.map(v => v.size))];
  const colors = [...new Set(variations.map(v => v.color))];

  // Trouver la variation actuelle
  const currentVariation = useMemo(() => {
    if (!selectedSize || !selectedColor) return null;
    return variations.find(v => v.size === selectedSize && v.color === selectedColor);
  }, [selectedSize, selectedColor, variations]);

  // Couleurs disponibles pour la taille sélectionnée (stock > 0)
  const availableColors = useMemo(() => {
    if (!selectedSize) return colors;
    return variations
      .filter(v => v.size === selectedSize && v.stock > 0)
      .map(v => v.color);
  }, [selectedSize, variations, colors]);

  // Tailles disponibles pour la couleur sélectionnée
  const availableSizes = useMemo(() => {
    if (!selectedColor) return sizes;
    return variations
      .filter(v => v.color === selectedColor && v.stock > 0)
      .map(v => v.size);
  }, [selectedColor, variations, sizes]);

  const updateQuantity = (delta: number) => {
    if (currentVariation) {
      const newQuantity = quantity + delta;
      if (newQuantity >= 1 && newQuantity <= currentVariation.stock) {
        setQuantity(newQuantity);
        onVariationChange(currentVariation, newQuantity);
      }
    }
  };

  const handleSizeChange = (size: string) => {
    setSelectedSize(size);
    setSelectedColor(''); // Réinitialiser couleur
    setQuantity(1);
  };

  const handleColorChange = (color: string) => {
    setSelectedColor(color);
    setQuantity(1);
    const variation = variations.find(v => v.size === selectedSize && v.color === color);
    if (variation) onVariationChange(variation, 1);
  };

  return (
    <View style={styles.container}>
      <Text style={styles.label}>Taille :</Text>
      <View style={styles.optionsRow}>
        {sizes.map(size => (
          <TouchableOpacity
            key={size}
            style={[
              styles.option,
              selectedSize === size && styles.optionSelected,
              !availableSizes.includes(size) && styles.optionDisabled
            ]}
            onPress={() => availableSizes.includes(size) && handleSizeChange(size)}
            disabled={!availableSizes.includes(size)}
          >
            <Text style={[styles.optionText, selectedSize === size && styles.optionTextSelected]}>
              {size}
            </Text>
          </TouchableOpacity>
        ))}
      </View>

      <Text style={styles.label}>Couleur :</Text>
      <View style={styles.optionsRow}>
        {colors.map(color => (
          <TouchableOpacity
            key={color}
            style={[
              styles.option,
              selectedColor === color && styles.optionSelected,
              !availableColors.includes(color) && styles.optionDisabled
            ]}
            onPress={() => availableColors.includes(color) && handleColorChange(color)}
            disabled={!availableColors.includes(color)}
          >
            <Text style={[styles.optionText, selectedColor === color && styles.optionTextSelected]}>
              {color}
            </Text>
          </TouchableOpacity>
        ))}
      </View>

      {currentVariation && (
        <>
          <Text style={styles.label}>
            Prix : {currentVariation.price} €
          </Text>
          <Text style={styles.label}>
            Stock disponible : {currentVariation.stock}
          </Text>
          <View style={styles.quantityRow}>
            <TouchableOpacity onPress={() => updateQuantity(-1)} style={styles.qtyButton}>
              <Text style={styles.qtyButtonText}>-</Text>
            </TouchableOpacity>
            <Text style={styles.quantity}>{quantity}</Text>
            <TouchableOpacity onPress={() => updateQuantity(1)} style={styles.qtyButton}>
              <Text style={styles.qtyButtonText}>+</Text>
            </TouchableOpacity>
          </View>
        </>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: { padding: 16 },
  label: { fontSize: 16, fontWeight: '600', marginTop: 12, marginBottom: 8 },
  optionsRow: { flexDirection: 'row', flexWrap: 'wrap', gap: 8 },
  option: { paddingHorizontal: 16, paddingVertical: 8, borderRadius: 8, backgroundColor: '#f0f0f0', borderWidth: 1, borderColor: '#ddd' },
  optionSelected: { backgroundColor: '#0066cc', borderColor: '#0066cc' },
  optionDisabled: { opacity: 0.4 },
  optionText: { color: '#333' },
  optionTextSelected: { color: '#fff' },
  quantityRow: { flexDirection: 'row', alignItems: 'center', justifyContent: 'center', marginTop: 16 },
  qtyButton: { width: 40, height: 40, backgroundColor: '#ddd', alignItems: 'center', justifyContent: 'center', borderRadius: 8 },
  qtyButtonText: { fontSize: 20, fontWeight: 'bold' },
  quantity: { fontSize: 18, marginHorizontal: 20, width: 40, textAlign: 'center' },
});
