import React from 'react';
import { View, Text, FlatList, StyleSheet } from 'react-native';
import Icon from 'react-native-vector-icons/FontAwesome';

interface Review {
  id: number;
  author: string;
  rating: number;
  comment: string;
  date: string;
}

interface StarRatingProps {
  rating: number; // sur 5
  size?: number;
  showNumber?: boolean;
}

const StarRating: React.FC<StarRatingProps> = ({ rating, size = 16, showNumber = false }) => {
  const fullStars = Math.floor(rating);
  const hasHalfStar = rating - fullStars >= 0.5;
  const emptyStars = 5 - fullStars - (hasHalfStar ? 1 : 0);

  return (
    <View style={{ flexDirection: 'row', alignItems: 'center' }}>
      {[...Array(fullStars)].map((_, i) => (
        <Icon key={`full-${i}`} name="star" size={size} color="#FFD700" />
      ))}
      {hasHalfStar && <Icon name="star-half" size={size} color="#FFD700" />}
      {[...Array(emptyStars)].map((_, i) => (
        <Icon key={`empty-${i}`} name="star-o" size={size} color="#FFD700" />
      ))}
      {showNumber && <Text style={{ marginLeft: 8 }}>({rating.toFixed(1)})</Text>}
    </View>
  );
};

interface ReviewListProps {
  reviews: Review[];
}

const ReviewList: React.FC<ReviewListProps> = ({ reviews }) => {
  const averageRating = reviews.reduce((acc, r) => acc + r.rating, 0) / reviews.length;

  const renderReviewItem = ({ item }: { item: Review }) => (
    <View style={styles.reviewCard}>
      <View style={styles.reviewHeader}>
        <Text style={styles.author}>{item.author}</Text>
        <Text style={styles.date}>{new Date(item.date).toLocaleDateString('fr-FR')}</Text>
      </View>
      <StarRating rating={item.rating} size={14} />
      <Text style={styles.comment}>{item.comment}</Text>
    </View>
  );

  return (
    <View style={styles.container}>
      <View style={styles.averageContainer}>
        <Text style={styles.averageLabel}>Note moyenne :</Text>
        <StarRating rating={averageRating} size={24} showNumber />
      </View>
      <Text style={styles.sectionTitle}>Avis clients ({reviews.length})</Text>
      <FlatList
        data={reviews}
        renderItem={renderReviewItem}
        keyExtractor={(item) => item.id.toString()}
        showsVerticalScrollIndicator={false}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: { padding: 16 },
  averageContainer: { flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16, paddingBottom: 12, borderBottomWidth: 1, borderBottomColor: '#eee' },
  averageLabel: { fontSize: 16, fontWeight: 'bold' },
  sectionTitle: { fontSize: 18, fontWeight: 'bold', marginBottom: 12 },
  reviewCard: { backgroundColor: '#f9f9f9', borderRadius: 8, padding: 12, marginBottom: 12 },
  reviewHeader: { flexDirection: 'row', justifyContent: 'space-between', marginBottom: 6 },
  author: { fontWeight: 'bold', fontSize: 14 },
  date: { fontSize: 12, color: '#666' },
  comment: { marginTop: 8, fontSize: 14, color: '#333', lineHeight: 20 },
});

export { StarRating, ReviewList };
