import React, { useState, useEffect } from 'react';
import { View, Text, ScrollView, Button, Alert } from 'react-native';
import { useQuery } from '@tanstack/react-query';
import useCartStore from '../store/cartStore';
import ImageCarousel from '../components/ImageCarousel';
import ProductVariationSelector from '../components/ProductVariationSelector';
import { ReviewList } from '../components/StarRating';

interface ProductDetailScreenProps {
  route: { params: { productId: number } };
}

const ProductDetailScreen: React.FC<ProductDetailScreenProps> = ({ route }) => {
  const { productId } = route.params;
  const addToCart = useCartStore((state) => state.addItem);
  const [selectedVariation, setSelectedVariation] = useState<any>(null);
  const [quantity, setQuantity] = useState(1);

  const { data: product, isLoading } = useQuery({
    queryKey: ['product', productId],
    queryFn: () => fetchProduct(productId),
  });

  const handleVariationChange = (variation: any, qty: number) => {
    setSelectedVariation(variation);
    setQuantity(qty);
  };

  const handleAddToCart = () => {
    if (!selectedVariation) {
      Alert.alert('Erreur', 'Veuillez sélectionner une taille et une couleur');
      return;
    }
    addToCart({
      productId: product.id,
      variationId: selectedVariation.id,
      name: product.name,
      size: selectedVariation.size,
      color: selectedVariation.color,
      quantity: quantity,
      price: selectedVariation.price,
    });
    Alert.alert('Succès', 'Produit ajouté au panier');
  };

  if (isLoading) return <Text>Chargement...</Text>;

  return (
    <ScrollView>
      <ImageCarousel images={product.images} />
      <View style={{ padding: 16 }}>
        <Text style={{ fontSize: 24, fontWeight: 'bold' }}>{product.name}</Text>
        <Text style={{ fontSize: 20, color: '#e67e22', marginTop: 8 }}>
          {selectedVariation ? `${selectedVariation.price} €` : `${product.basePrice} €`}
        </Text>
        <Text style={{ marginTop: 12 }}>{product.description}</Text>

        <ProductVariationSelector
          variations={product.variations}
          onVariationChange={handleVariationChange}
        />

        <ReviewList reviews={product.reviews} />

        <Button title="Ajouter au panier" onPress={handleAddToCart} />
      </View>
    </ScrollView>
  );
};

export default ProductDetailScreen;
